const isAliveNextGeneration = (wasAlive: boolean, liveNeighborCount: number): boolean =>
  liveNeighborCount === 3 || (wasAlive && liveNeighborCount === 2);

const countLiveNeighborsByCell = (liveCells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const liveCell of liveCells) {
    for (const neighbor of neighborsOf(liveCell)) {
      const key = cellKey(neighbor);
      const entry = counts.get(key);
      if (entry) entry.count++;
      else counts.set(key, { cell: neighbor, count: 1 });
    }
  }
  return counts;
};

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const candidateCells = countLiveNeighborsByCell(liveCells);

  return Array.from(candidateCells)
    .filter(([key, { count }]) => isAliveNextGeneration(liveKeys.has(key), count))
    .map(([, { cell }]) => cell);
}
